import sqlite3

def get_order(user_id, order_id):
    conn = sqlite3.connect('database.db')
    cursor = conn.cursor()
    query = 'SELECT * FROM orders WHERE user_id=? AND id=?'
    result = cursor.execute(query, (user_id, order_id)).fetchone()
    if result:
        return {c[0]: c[1] for c in result}
    else:
        return None
